#include <bits/stdc++.h>
using namespace std;

const int mod = 1e9+7;
int n, a, b, c;
int f[200005];

int main() {
    cin >> n >> a >> b >> c;
    for (int i = 0; i <= c; i++) {
        f[i] = 1;
    }
    for (int i = c + 1; i <= n; i++) {
        f[i] = (f[max(0, i - a)] + f[max(0, i - b)]) % mod;
    }
    cout << f[n];
    return 0;
}
